def lcs_length(a,b):
    # dynamic programming; but strings are short
    n, m = len(a), len(b)
    dp = [0]*(m+1)
    for i in range(1, n+1):
        prev=0
        for j in range(1, m+1):
            tmp = dp[j]
            if a[i-1]==b[j-1]:
                dp[j] = prev+1
            else:
                dp[j] = max(dp[j], dp[j-1])
            prev = tmp
    return dp[m]

def sim_ratio(a,b):
    # normalized LCS over max length
    return lcs_length(a,b)/max(len(a),len(b))
